const counter = require('./metrics').counter('api_version_requests_total', ['version']);
const SUNSET = { v1: 'Sat, 01 Aug 2026 00:00:00 GMT' };

function versionMiddleware(version) {
  return (req, res, next) => {
    req.apiVersion = version;
    counter.inc({ version });
    if (SUNSET[version]) {
      res.set('Deprecation', 'true');
      res.set('Sunset', SUNSET[version]);
    }
    next();
  };
}
module.exports = { versionMiddleware, SUNSET };

