CREATE TABLE idempotency_keys (
  key text PRIMARY KEY,
  request_hash text NOT NULL,
  status text NOT NULL DEFAULT 'pending',
  response jsonb,
  created_at timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX idx_idem_created ON idempotency_keys (created_at);

import { Injectable } from '@nestjs/common';
import { createHash } from 'crypto';
import { Pool } from 'pg';
import Redis from 'ioredis';

@Injectable()
export class IdempotencyService {
  constructor(private pg: Pool, private redis: Redis) {}

  hash(body: unknown) { return createHash('sha256').update(JSON.stringify(body)).digest('hex'); }

  async claim(key: string, reqHash: string) {
    const r = await this.pg.query(
      `INSERT INTO idempotency_keys(key, request_hash) VALUES($1,$2)
       ON CONFLICT (key) DO NOTHING RETURNING key`, [key, reqHash]);
    return r.rowCount === 1; // true = we own it
  }

  async get(key: string) {
    const r = await this.pg.query('SELECT request_hash, status, response FROM idempotency_keys WHERE key=$1', [key]);
    return r.rows[0] ?? null;
  }

  async complete(key: string, response: unknown) {
    await this.pg.query(`UPDATE idempotency_keys SET status='done', response=$2 WHERE key=$1`, [key, response]);
  }
}

import { Controller, Post, Body, Headers, ConflictException } from '@nestjs/common';
import { PaymentsService } from './payments.service';
import { IdempotencyService } from './idempotency.service';

@Controller('payments')
export class PaymentsController {
  constructor(private svc: PaymentsService, private idem: IdempotencyService) {}

  @Post()
  async create(@Body() dto: CreatePaymentDto, @Headers('idempotency-key') key?: string) {
    if (!key) { const c = await this.svc.charge(dto); return { id: c.id, status: c.status }; }
    const reqHash = this.idem.hash(dto);
    const owned = await this.idem.claim(key, reqHash);
    if (!owned) {
      const rec = await this.idem.get(key);
      if (rec.request_hash !== reqHash) throw new ConflictException('idempotency_key_reuse');
      if (rec.status === 'done') return rec.response;
      // in-flight: poll briefly
      for (let i=0;i<20;i++){ await new Promise(r=>setTimeout(r,100)); const x=await this.idem.get(key); if(x.status==='done') return x.response; }
      throw new ConflictException('still_processing');
    }
    const c = await this.svc.charge(dto);
    const body = { id: c.id, status: c.status };
    await this.idem.complete(key, body);
    return body;
  }
}

