from rest_framework.versioning import BaseVersioning
import re

class AcceptHeaderVersioning(BaseVersioning):
    default_version = 'v1'
    allowed = {'v1', 'v2'}
    pattern = re.compile(r'application/vnd\.ehr\.(v\d+)\+json')

    def determine_version(self, request, *a, **k):
        m = self.pattern.search(request.META.get('HTTP_ACCEPT', ''))
        v = m.group(1) if m else self.default_version
        return v if v in self.allowed else self.default_version

