function buildLinks(base, page, per, total) {
  const last = Math.max(1, Math.ceil(total / per));
  const mk = (p, rel) => `<${base}?page=${p}&per=${per}>; rel="${rel}"`;
  const parts = [];
  if (page < last) parts.push(mk(page + 1, 'next'));
  if (page > 1) parts.push(mk(page - 1, 'prev'));
  parts.push(mk(last, 'last'));
  parts.push(mk(1, 'first'));
  return parts.join(', ');
}
module.exports = { buildLinks };

