const crypto = require('crypto');

router.get('/reports', async (req, res) => {
  const page = Math.max(1, +req.query.page || 1);
  const per = Math.min(500, +req.query.per || 100);
  const filterHash = crypto.createHash('md5').update(JSON.stringify(req.query.filter || {})).digest('hex');
  let total = +(await redis.get(`reports:count:${filterHash}`));
  if (!total) {
    total = await db.reports.count(req.query.filter);
    await redis.set(`reports:count:${filterHash}`, total, 'EX', 30);
  }
  const rows = await db.reports.find({ filter: req.query.filter, offset: (page-1)*per, limit: per });
  res.set('X-Total-Count', String(total));
  res.set('Link', buildLinks(`${req.protocol}://${req.get('host')}${req.path}`, page, per, total));
  res.json(rows);
});

