const LEGACY = '2024-01';

module.exports = (required) => (req, res, next) => {
  const scopes = req.token.scopes;
  const ver = req.token.api_version;
  if (scopes.includes(required)) return next();
  if (ver === LEGACY && scopes.includes('write:all')) {
    audit.legacyScopeGrant(req.token.app_id, required);
    return next();
  }
  return res.status(403).json({ error: 'insufficient_scope', required });
};

