import { NextResponse } from 'next/server';

const ENVELOPE_VERSION = '2026-06';

export function respond(req: Request, data: unknown, meta?: Record<string, unknown>) {
  const ver = req.headers.get('x-api-version');
  const reqId = req.headers.get('x-request-id') ?? crypto.randomUUID();
  if (ver && ver >= ENVELOPE_VERSION) {
    return NextResponse.json({ data, meta: meta ?? {}, requestId: reqId }, { headers: { 'x-request-id': reqId } });
  }
  return NextResponse.json(data, { headers: { 'x-request-id': reqId } });
}

export function respondError(req: Request, status: number, code: string, message: string) {
  const reqId = req.headers.get('x-request-id') ?? crypto.randomUUID();
  return NextResponse.json({ error: { code, message }, requestId: reqId }, { status, headers: { 'x-request-id': reqId } });
}

