router.put('/orgs/:id/settings', async (req, res) => {
  const ifMatch = (req.get('If-Match') || '').replace(/"/g, '');
  if (!ifMatch) {
    // legacy path: still last-write-wins but bump version
    const s = await db.settings.bumpAndUpdate(req.params.id, req.body);
    res.set('ETag', `"${s.version}"`);
    return res.json(s.data);
  }
  const result = await db.query(
    `UPDATE org_settings SET data = $1, version = version + 1
     WHERE id = $2 AND version = $3 RETURNING version, data`,
    [req.body, req.params.id, Number(ifMatch)]);
  if (result.rowCount === 0) return res.status(412).json({ error: 'precondition_failed', message: 'Settings changed; re-fetch and retry.' });
  res.set('ETag', `"${result.rows[0].version}"`);
  res.json(result.rows[0].data);
});

