const ALLOWED = new Set(['buyer', 'items']);

function parseInclude(raw) {
  const reqd = (raw || '').split(',').map(s => s.trim()).filter(Boolean);
  const bad = reqd.filter(i => !ALLOWED.has(i));
  if (bad.length) { const e = new Error(`unsupported include: ${bad.join(',')}`); e.status = 400; throw e; }
  if (reqd.length > 5) { const e = new Error('too many includes'); e.status = 400; throw e; }
  return new Set(reqd);
}
module.exports = { parseInclude };

const { parseInclude } = require('../include');

router.get('/orders', async (req, res, next) => {
  try {
    const inc = parseInclude(req.query.include);
    const orders = await db.orders.findByPartner(req.partner.id);
    const base = orders.map(o => ({ id: o.id, buyer_id: o.buyer_id, total: o.total_cents }));
    if (inc.has('buyer')) {
      const ids = [...new Set(orders.map(o => o.buyer_id))];
      const buyers = await db.users.findReadableByIds(req.partner.id, ids); // batch + authz
      const byId = new Map(buyers.map(b => [b.id, b]));
      base.forEach(o => { o.buyer = byId.get(o.buyer_id) || null; });
    }
    if (inc.has('items')) {
      const orderIds = orders.map(o => o.id);
      const items = await db.items.findByOrderIds(orderIds); // single batched query
      const grouped = items.reduce((m, it) => ((m[it.order_id] ??= []).push(it), m), {});
      base.forEach(o => { o.items = grouped[o.id] || []; });
    }
    res.json(base);
  } catch (e) { next(e); }
});

