package handlers

import (
    "fmt"
    "strings"
)

var allowed = map[string]bool{
    "id": true, "name": true, "plan": true, "status": true,
    "mrr_cents": true, "owner_email": true, // sensitive: owner_email
}
var sensitive = map[string]bool{"owner_email": true, "mrr_cents": true}

func selectColumns(raw string, canSeeSensitive bool) ([]string, error) {
    if raw == "" {
        return []string{"id", "name", "plan", "status", "mrr_cents", "owner_email"}, nil // default = all
    }
    var cols []string
    for _, f := range strings.Split(raw, ",") {
        f = strings.TrimSpace(f)
        if !allowed[f] {
            return nil, fmt.Errorf("unknown field: %s", f)
        }
        if sensitive[f] && !canSeeSensitive {
            continue // silently drop fields the caller can't see
        }
        cols = append(cols, f)
    }
    if len(cols) == 0 {
        cols = []string{"id"}
    }
    return cols, nil
}

func ListAccounts(w http.ResponseWriter, r *http.Request) {
    cols, err := selectColumns(r.URL.Query().Get("fields[accounts]"), canSeeSensitive(r))
    if err != nil {
        http.Error(w, err.Error(), http.StatusBadRequest)
        return
    }
    q := fmt.Sprintf("SELECT %s FROM accounts WHERE org_id=$1", strings.Join(cols, ", "))
    rows, err := db.Query(q, orgID(r))
    if err != nil { http.Error(w, "query failed", 500); return }
    json.NewEncoder(w).Encode(scanDynamic(rows, cols))
}

