const transformers = {
  '2024-06': (e) => ({ type: e.type, amount: e.amount_cents / 100, currency: e.currency }),
  '2026-06': (e) => ({ type: e.type, data: { amount: { value: e.amount_cents, currency: e.currency, unit: 'minor' } } }),
};

function transform(version, event) {
  const t = transformers[version] || transformers['2024-06'];
  return t(event);
}
module.exports = { transform, versions: Object.keys(transformers) };

const { transform } = require('./transformers');

async function dispatch(event, endpoint) {
  const version = endpoint.webhook_version || '2024-06';
  const body = transform(version, event);
  const raw = JSON.stringify(body);
  const sig = sign(raw, endpoint.secret); // signature covers the versioned body
  await post(endpoint.url, raw, {
    'Content-Type': 'application/json',
    'X-Signature': sig,
