async function check(key, limit, windowSec) {
  const count = await redis.incr(`rl:${key}`);
  if (count === 1) await redis.expire(`rl:${key}`, windowSec);
  return count <= limit; // boolean only
}
module.exports = { check };

const redis = require('./redis');

// Atomic: incr, set TTL on first hit, return [count, ttl]
const LUA = `
local c = redis.call('INCR', KEYS[1])
if c == 1 then redis.call('EXPIRE', KEYS[1], ARGV[1]) end
local ttl = redis.call('TTL', KEYS[1])
return {c, ttl}`;

async function check(key, limit, windowSec) {
  const [count, ttl] = await redis.eval(LUA, 1, `rl:${key}`, windowSec);
  return { allowed: count <= limit, limit, remaining: Math.max(0, limit - count), resetSec: ttl };
}
module.exports = { check };

const { check } = require('../limiter');

function rateLimit(planLimits) {
  return async (req, res, next) => {
    const { limit, windowSec } = planLimits[req.apiKey.plan] || planLimits.default;
    const r = await check(req.apiKey.id, limit, windowSec);
    res.set('RateLimit-Limit', String(r.limit));
    res.set('RateLimit-Remaining', String(r.remaining));
    res.set('RateLimit-Reset', String(r.resetSec));
    if (!r.allowed) {
      res.set('Retry-After', String(r.resetSec));
      return res.status(429).json({ error: 'rate_limited', retry_after: r.resetSec });
    }
    next();
  };
}
module.exports = { rateLimit };

