  const errors = [];
  if (!it.client_ref) errors.push('client_ref required');
  if (!it.address || !it.address.zip) errors.push('address.zip required');
  if (!it.weight_g || it.weight_g <= 0) errors.push('weight_g must be > 0');
  return errors;
}
