router.post('/shipments/bulk', async (req, res) => {
  const items = req.body.shipments || [];
  if (items.length > 500) return res.status(400).json({ error: 'batch_too_large' });
  const results = new Array(items.length);
  const valid = [];
  items.forEach((it, i) => {
    const errs = validateShipment(it);
    if (errs.length) results[i] = { index: i, status: 'error', errors: errs };
    else valid.push({ i, it });
  });
  if (valid.length) {
    const rows = await db.shipments.bulkInsert(
      valid.map(v => v.it)); // single multi-row INSERT ... ON CONFLICT(client_ref) DO NOTHING RETURNING
    const byRef = new Map(rows.map(r => [r.client_ref, r]));
    valid.forEach(v => {
      const r = byRef.get(v.it.client_ref);
      results[v.i] = r
        ? { index: v.i, status: 'created', id: r.id }
        : { index: v.i, status: 'duplicate', client_ref: v.it.client_ref }; // ON CONFLICT skipped
    });
  }
  const created = results.filter(r => r.status === 'created').length;
  res.status(207).json({ summary: { total: items.length, created, failed: items.length - created }, results });
});

