async function getUpdatedAt(id) {
  const cached = await redis.get(`cat:upd:${id}`);
  if (cached) return Number(cached);
  const row = await db.query('SELECT extract(epoch from updated_at) AS u FROM catalog WHERE id=$1', [id]);
  if (!row.rows[0]) return null;
  const u = Math.floor(row.rows[0].u);
  await redis.set(`cat:upd:${id}`, u, 'EX', 300);
  return u;
}
async function invalidate(id) { await redis.del(`cat:upd:${id}`); }
