  if (upd === null) return res.status(404).json({ error: 'not_found' });
  const etag = `"${upd}"`;
  const lastMod = new Date(upd * 1000).toUTCString();
  const inm = req.get('If-None-Match');
  const ims = req.get('If-Modified-Since');
  if (inm === etag || (ims && Date.parse(ims) >= upd * 1000)) {
    res.set('ETag', etag); res.set('Last-Modified', lastMod);
    return res.status(304).end(); // no body, no full read
  }
  const item = await db.catalog.findById(req.params.id);
  res.set('ETag', etag); res.set('Last-Modified', lastMod); res.set('Cache-Control', 'public, max-age=60');
  res.json(item);
});

