function resolveLimit(raw) {
  if (raw === undefined) return { limit: DEFAULT };
  const n = Number(raw);
  if (!Number.isInteger(n) || n < 1) return { error: 'limit must be a positive integer' };
  if (n > MAX) return { error: `limit exceeds maximum of ${MAX}`, max: MAX };
  return { limit: n };
}
