class ProductSerializer(serializers.Serializer):
    id = serializers.IntegerField()
    name = serializers.CharField()
    options = serializers.SerializerMethodField()
    def get_options(self, p):
        return ';'.join(f'{o.key}:{o.value}' for o in p.options)

class ProductBaseSerializer(serializers.Serializer):
    id = serializers.IntegerField()
    name = serializers.CharField()
    options = serializers.SerializerMethodField()
    def get_options(self, p):
        return [{'key': o.key, 'value': o.value} for o in p.options]  # richest structured form

# Each transform downgrades the base representation to an older version's shape.
def to_v1(data: dict) -> dict:
    d = dict(data)
    d['options'] = ';'.join(f"{o['key']}:{o['value']}" for o in data['options'])  # flatten
    return d

def to_v2(data: dict) -> dict:
    return data  # v2 == base structured shape

