const REGISTRY = {
  status: { type: 'enum', values: ['pending','shipped','delivered'], ops: ['eq','in'], indexed: true },
  carrier: { type: 'string', ops: ['eq'], indexed: true },
  weight_g: { type: 'int', ops: ['eq','gt','lt'], indexed: false },
};
const OP_SQL = { eq: '=', gt: '>', lt: '<', in: 'IN' };

function compile(filters) {
  const clauses = []; const params = []; let i = 1;
  for (const [field, raw] of Object.entries(filters)) {
    const spec = REGISTRY[field];
    if (!spec) throw httpErr(400, `unknown filter field: ${field}`);
    const [op, value] = String(raw).split(':');
    if (!spec.ops.includes(op)) throw httpErr(400, `op ${op} not allowed on ${field}`);
    if (!spec.indexed && op !== 'eq') throw httpErr(400, `range filter on non-indexed ${field} not allowed`);
    const v = coerce(spec.type, value);
    if (op === 'in') { const list = v.split(','); clauses.push(`${field} IN (${list.map(()=>'$'+i++).join(',')})`); params.push(...list); }
    else { clauses.push(`${field} ${OP_SQL[op]} $${i++}`); params.push(v); }
  }
  return { sql: clauses.length ? 'WHERE ' + clauses.join(' AND ') : '', params };
}
function coerce(t, v){ if(t==='int'){ const n=Number(v); if(!Number.isInteger(n)) throw httpErr(400,'int expected'); return n;} return v; }
function httpErr(s,m){ const e=new Error(m); e.status=s; return e; }
module.exports = { compile };

