router.get('/shipments', async (req, res, next) => {
  try {
    // legacy ?status=shipped -> grammar filter[status]=eq:shipped
    const filters = { ...req.query.filter };
    if (req.query.status && !filters.status) filters.status = `eq:${req.query.status}`;
    const { sql, params } = compile(filters);
    const rows = await db.query(`SELECT * FROM shipments ${sql} LIMIT 200`, params);
    res.json(rows.rows);
  } catch (e) { next(e); }
});

