const { Transform } = require('stream');
const COLUMNS = ['id', 'date', 'amount', 'currency']; // stable order

function esc(v) {
  const s = v == null ? '' : String(v);
  return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
}
function csvStream() {
  let header = false;
  return new Transform({ objectMode: true, transform(row, _e, cb) {
    let out = header ? '' : COLUMNS.join(',') + '\n';
    header = true;
    out += COLUMNS.map(c => esc(row[c])).join(',') + '\n';
    cb(null, out);
  }});
}
module.exports = { csvStream, COLUMNS };

const { csvStream } = require('../export/csv');

router.get('/reports/export', async (req, res) => {
  const cursor = db.reports.cursor(req.query); // streams from DB, no full buffer
  const accept = req.get('Accept') || '';
  if (accept.includes('text/csv')) {
    res.type('text/csv').set('Content-Disposition', 'attachment; filename=report.csv');
    cursor.stream().pipe(csvStream()).pipe(res);
  } else {
    res.type('application/json');
    res.write('[');
    let first = true;
    cursor.stream()
      .on('data', r => { res.write((first ? '' : ',') + JSON.stringify(r)); first = false; })
      .on('end', () => res.end(']'))
      .on('error', () => res.destroy());
  }
});

