const crypto = require('crypto');
const redis = require('../redis');
const SKEW_MS = 5 * 60 * 1000;

async function verifySignature(req, partner) {
  const keyId = req.get('X-Key-Id');
  const ts = Number(req.get('X-Timestamp'));
  const nonce = req.get('X-Nonce');
  const sig = req.get('X-Signature');
  if (!keyId || !ts || !nonce || !sig) return false;
  if (Math.abs(Date.now() - ts) > SKEW_MS) return false; // skew/replay window
  const bodyHash = crypto.createHash('sha256').update(req.rawBody || '').digest('hex');
  const canonical = [req.method, req.path, bodyHash, ts, nonce].join('\n');
  const expected = crypto.createHmac('sha256', partner.secret).update(canonical).digest('hex');
  if (!crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expected))) return false;
  const fresh = await redis.set(`nonce:${keyId}:${nonce}`, '1', 'NX', 'PX', SKEW_MS);
  return fresh === 'OK'; // false => nonce replayed
}
module.exports = { verifySignature };

const { verifySignature } = require('./sign');

module.exports = async (req, res, next) => {
  const keyId = req.get('X-Key-Id') || req.get('X-Api-Key');
  const partner = await db.partners.findByKey(keyId);
  if (!partner) return res.status(401).json({ error: 'unauthorized' });
  if (partner.require_signing) {
    if (!(await verifySignature(req, partner))) return res.status(401).json({ error: 'invalid_signature' });
  } else if (req.get('X-Signature')) {
    // partner sending signatures during migration: verify if present
    if (!(await verifySignature(req, partner))) return res.status(401).json({ error: 'invalid_signature' });
  }
  req.partner = partner;
  next();
};

