const { encode, decode } = require('../cursor');

async function commentsConnection(post, { first, after, last, before }) {
  const limit = Math.min(100, first || last || 20);
  const fetch = limit + 1; // over-fetch to compute has*Page
  let rows, backward = !!(last || before);
  if (!backward) {
    const cur = after ? decode(after) : null;
    rows = await db.query(
      `SELECT id, body, created_at FROM comments WHERE post_id=$1 ${cur ? 'AND (created_at,id) > ($2,$3)' : ''} ORDER BY created_at ASC, id ASC LIMIT $${cur?4:2}`,
      cur ? [post.id, cur.t, cur.i, fetch] : [post.id, fetch]);
  } else {
    const cur = before ? decode(before) : null;
    rows = await db.query(
      `SELECT id, body, created_at FROM comments WHERE post_id=$1 ${cur ? 'AND (created_at,id) < ($2,$3)' : ''} ORDER BY created_at DESC, id DESC LIMIT $${cur?4:2}`,
      cur ? [post.id, cur.t, cur.i, fetch] : [post.id, fetch]);
    rows.rows.reverse();
  }
  const hasMore = rows.rows.length > limit;
  const page = hasMore ? (backward ? rows.rows.slice(rows.rows.length - limit) : rows.rows.slice(0, limit)) : rows.rows;
  const edges = page.map(r => ({ node: r, cursor: encode(r) }));
  return {
    edges,
    pageInfo: {
      hasNextPage: backward ? !!after : hasMore,
      hasPreviousPage: backward ? hasMore : !!after,
      startCursor: edges[0]?.cursor || null,
      endCursor: edges[edges.length-1]?.cursor || null,
    },
  };
}
module.exports = { Post: { commentsConnection } };

