const { DateTime } = require('luxon');
const CANON_ZONE = 'America/New_York'; // zone the legacy string represented

function serializeSlot(s, version) {
  const utc = DateTime.fromJSDate(s.start_utc, { zone: 'utc' });
  const out = {
    id: s.id,
    start_at: utc.toISO(),                                   // RFC 3339 UTC, e.g. 2026-06-21T14:00:00.000Z
    start_time: utc.setZone(CANON_ZONE).toFormat('yyyy-MM-dd HH:mm'), // legacy local, DST-correct
  };
  return out;
}
module.exports = { serializeSlot, CANON_ZONE };

const { DateTime } = require('luxon');
const { CANON_ZONE } = require('./serialize');

function parseStart(input) {
  if (input.start_at) {
    const dt = DateTime.fromISO(input.start_at, { setZone: true });
    if (!dt.isValid) throw new Error('invalid start_at');
    return dt.toUTC().toJSDate(); // honors provided offset
  }
  if (input.start_time) {
    const dt = DateTime.fromFormat(input.start_time, 'yyyy-MM-dd HH:mm', { zone: CANON_ZONE });
    return dt.toUTC().toJSDate(); // interpret legacy local in canonical zone
  }
  throw new Error('start_at or start_time required');
}
module.exports = { parseStart };

