package server

import (
    "google.golang.org/genproto/googleapis/rpc/errdetails"
    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/status"
)

const Domain = "transfers.acme.com"

func problem(code codes.Code, reason, msg string, md map[string]string) error {
    st := status.New(code, msg)
    st, _ = st.WithDetails(&errdetails.ErrorInfo{Reason: reason, Domain: Domain, Metadata: md})
    return st.Err()
}

func (s *Svc) Transfer(ctx context.Context, r *pb.TransferReq) (*pb.TransferResp, error) {
    if balance(r.From) < r.Amount {
        return nil, problem(codes.FailedPrecondition, "INSUFFICIENT_FUNDS", "Insufficient funds", map[string]string{"account": r.From})
    }
    if frozen(r.From) {
        return nil, problem(codes.FailedPrecondition, "ACCOUNT_FROZEN", "Account is frozen", map[string]string{"account": r.From})
    }
    return doTransfer(r)
}

func reasonOf(err error) string {
    st, _ := status.FromError(err)
    for _, d := range st.Details() {
        if info, ok := d.(*errdetails.ErrorInfo); ok {
            return info.Reason
        }
    }
    return ""
}
// usage: switch reasonOf(err) { case "INSUFFICIENT_FUNDS": ...; case "ACCOUNT_FROZEN": ... }

